// Daily Drift Detector (ADR-001 Phase 3)
// Checks for configuration drift across the platform
const N8N_HOST = $vars.N8N_HOST;
const API_KEY = $vars.N8N_INTERNAL_API_KEY;
const drifts = [];
const timestamp = new Date().toISOString();

// === CHECK 1: Registry client coverage ===
// Every handler-type domain should have client=all
const REG_TABLE = $vars.REGISTRY_V2_API_TABLE_ID;
try {
  const regResp = await this.helpers.httpRequest({
    method: 'GET', url: N8N_HOST + '/api/v1/data-tables/' + REG_TABLE + '/rows?limit=250',
    headers: {'X-N8N-API-KEY': API_KEY}, json: true
  });
  const rows = regResp.data || [];
  // Group by domain, find latest entry per domain
  const latest = {};
  for (const row of rows) {
    const d = row.api_name;
    if (!latest[d] || row.id > latest[d].id) latest[d] = row;
  }
  // Check each domain has client=all or is intentionally client-specific
  for (const [domain, row] of Object.entries(latest)) {
    if (row.client !== 'all' && row.enabled) {
      drifts.push({
        check: 'registry_client_coverage',
        severity: 'warning',
        domain: domain,
        message: 'Registry entry has client=' + row.client + ' instead of client=all. May block other clients.',
        row_id: row.id
      });
    }
    // Check handler-type entries have handler_workflow_id
    if (row.handler_workflow_id === '' || row.handler_workflow_id === null) {
      // Check if this domain has handler-type actions
      const ACT_TABLE = $vars.REGISTRY_V2_ACTION_TABLE_ID;
      try {
        const actResp = await this.helpers.httpRequest({
          method: 'GET', url: N8N_HOST + '/api/v1/data-tables/' + ACT_TABLE + '/rows?limit=250',
          headers: {'X-N8N-API-KEY': API_KEY}, json: true
        });
        const handlerActions = (actResp.data || []).filter(a => a.api_name === domain && a.body_mode === 'handler' && a.enabled);
        if (handlerActions.length > 0) {
          drifts.push({
            check: 'missing_handler',
            severity: 'critical',
            domain: domain,
            message: domain + ' has ' + handlerActions.length + ' handler-type actions but no handler_workflow_id in registry.',
            row_id: row.id
          });
        }
      } catch(e) {}
    }
  }
} catch(e) {
  drifts.push({check: 'registry_read', severity: 'critical', domain: 'platform', message: 'Could not read registry: ' + e.message});
}

// === CHECK 2: Hardcoded URL scan ===
try {
  const wfResp = await this.helpers.httpRequest({
    method: 'GET', url: N8N_HOST + '/api/v1/workflows?limit=200',
    headers: {'X-N8N-API-KEY': API_KEY}, json: true
  });
  for (const wf of (wfResp.data || [])) {
    for (const node of (wf.nodes || [])) {
      if (node.type === 'n8n-nodes-base.code') {
        const code = (node.parameters || {}).jsCode || '';
        if (code.includes('mmurawala.app.n8n.cloud')) {
          drifts.push({
            check: 'hardcoded_url',
            severity: 'critical',
            domain: wf.name,
            message: 'Hardcoded URL in node "' + node.name + '" of workflow ' + wf.id
          });
        }
      }
    }
  }
} catch(e) {
  drifts.push({check: 'workflow_scan', severity: 'warning', domain: 'platform', message: 'Could not scan workflows: ' + e.message});
}

// === CHECK 3: Credential health staleness ===
const HEALTH_TABLE = $vars.CREDENTIAL_HEALTH_TABLE_ID;
try {
  const healthResp = await this.helpers.httpRequest({
    method: 'GET', url: N8N_HOST + '/api/v1/data-tables/' + HEALTH_TABLE + '/rows?limit=250',
    headers: {'X-N8N-API-KEY': API_KEY}, json: true
  });
  const rows = healthResp.data || [];
  const latest = {};
  for (const row of rows) {
    if (!latest[row.domain] || row.id > latest[row.domain].id) latest[row.domain] = row;
  }
  const now = new Date();
  for (const [domain, row] of Object.entries(latest)) {
    if (row.last_checked_at) {
      const checked = new Date(row.last_checked_at);
      const daysSince = (now - checked) / (1000 * 60 * 60 * 24);
      if (daysSince > 7) {
        drifts.push({
          check: 'stale_health',
          severity: 'warning',
          domain: domain,
          message: 'Health data is ' + Math.floor(daysSince) + ' days old. Last checked: ' + row.last_checked_at
        });
      }
    }
  }
} catch(e) {}

// === BUILD REPORT ===
const critical = drifts.filter(d => d.severity === 'critical');
const warnings = drifts.filter(d => d.severity === 'warning');

const report = {
  timestamp,
  total_drifts: drifts.length,
  critical_count: critical.length,
  warning_count: warnings.length,
  drifts: drifts
};

// Alert to Slack if any critical drifts
if (critical.length > 0) {
  try {
    const slackUrl = N8N_HOST + '/webhook/handler-google-suite';
    const secret = $vars.GW_HANDLER_INTERNAL_SECRET;
    const alertLines = critical.map(d => '• *' + d.domain + '*: ' + d.message).join('\n');
    await this.helpers.httpRequest({
      method: 'POST', url: slackUrl,
      headers: {'x-handler-secret': secret, 'Content-Type': 'application/json'},
      body: JSON.stringify({
        domain: 'slack', action: 'post_message', client: 'ascend',
        params: {
          channel: '#n8n-alerts',
          text: ':warning: *Daily Drift Detector — ' + critical.length + ' critical drift(s) found*\n' + alertLines + '\n\nRun `get_platform_context` for details.'
        }
      })
    });
    report.slack_alerted = true;
  } catch(e) {
    report.slack_alerted = false;
    report.slack_error = e.message;
  }
}

// Log to changelog
const CHANGELOG_TABLE = $vars.PLATFORM_CHANGELOG_TABLE_ID;
if (CHANGELOG_TABLE) {
  try {
    await this.helpers.httpRequest({
      method: 'POST', url: N8N_HOST + '/api/v1/data-tables/' + CHANGELOG_TABLE + '/rows',
      headers: {'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json'},
      body: JSON.stringify({data: [{
        timestamp, category: 'drift_check', domain: 'platform',
        summary: 'Daily drift check: ' + critical.length + ' critical, ' + warnings.length + ' warnings',
        details: JSON.stringify(drifts.slice(0, 10)),
        session_id: 'drift-detector'
      }]})
    });
  } catch(e) {}
}

return [{json: report}];
